26	type StreamResult<T> = Pin<Box<dyn Stream<Item = Result<T, Status>> + Send + 'static>>;
27	pub const DEFAULT_RESPONSE_TIMEOUT_SECS: u64 = 300;
28	
29	/// 64 MiB — leaves headroom for multimodal inputs and OpenAI JSON pass-through bodies,
30	/// well above tonic's 4 MiB decode default.
31	pub const DEFAULT_GRPC_MAX_MESSAGE_SIZE: usize = 64 * 1024 * 1024;
32	
33	/// Resolve the per-message size cap (bytes) applied to the Tonic encoder/decoder.
34	//
35	// TODO(grpc-args): promote SGLANG_TONIC_PAYLOAD to a proper `--grpc-max-message-size`
36	// server argument once the launcher PR (3/4) wires server args through.
37	fn resolve_max_message_size() -> usize {
38	    match std::env::var("SGLANG_TONIC_PAYLOAD") {
39	        Ok(raw) => match raw.parse::<usize>() {
40	            Ok(n) if n > 0 => {
41	                tracing::info!(
42	                    bytes = n,
43	                    "Using SGLANG_TONIC_PAYLOAD override for gRPC max message size"
44	                );
45	                n
46	            }
47	            _ => {
48	                tracing::warn!(
49	                    value = %raw,
50	                    default = DEFAULT_GRPC_MAX_MESSAGE_SIZE,
51	                    "Ignoring invalid SGLANG_TONIC_PAYLOAD; using default"
52	                );
53	                DEFAULT_GRPC_MAX_MESSAGE_SIZE
54	            }
55	        },
56	        Err(_) => DEFAULT_GRPC_MAX_MESSAGE_SIZE,
57	    }
58	}
59	
60	/// Classify a bridge `PyErr` into the right gRPC `Status`.
61	///
62	/// `PyValueError` / `PyTypeError` mean the client sent bad input — surface as
63	/// `INVALID_ARGUMENT` so callers can distinguish them from server failures.
64	/// Everything else (typically `PyRuntimeError`, but also Python tracebacks
65	/// from inside the tokenizer manager) maps to `INTERNAL`.
66	fn pyerr_to_status(err: PyErr, context: &str) -> Status {
67	    let is_client_error = Python::with_gil(|py| {
68	        err.is_instance_of::<PyValueError>(py) || err.is_instance_of::<PyTypeError>(py)
69	    });
70	    let msg = format!("{}: {}", context, err);
71	    if is_client_error {
72	        Status::invalid_argument(msg)
73	    } else {
74	        Status::internal(msg)
75	    }
76	}
77	
78	async fn recv_chunk_with_timeout(
79	    receiver: &mut Receiver<ResponseChunk>,
80	    response_timeout: Duration,
81	    timeout_message: impl FnOnce() -> String,
82	) -> Result<Option<ResponseChunk>, Status> {
83	    timeout(response_timeout, receiver.recv())
84	        .await
85	        .map_err(|_| Status::deadline_exceeded(timeout_message()))
86	}
87	
88	struct RequestAbortGuard {
89	    bridge: Arc<PyBridge>,
90	    rid: String,
91	    armed: bool,
92	}
93	
94	impl RequestAbortGuard {
95	    fn new(bridge: Arc<PyBridge>, rid: impl Into<String>) -> Self {
96	        Self {
97	            bridge,
98	            rid: rid.into(),
99	            armed: true,
100	        }
101	    }
102	
103	    fn disarm(&mut self) {
104	        self.armed = false;
105	    }
106	
107	    fn abort_now(&mut self) {
108	        if self.armed {
109	            self.armed = false;
110	            spawn_abort(self.bridge.clone(), self.rid.clone());
111	        }
112	    }
113	}
114	
115	impl Drop for RequestAbortGuard {
116	    fn drop(&mut self) {
117	        if self.armed {
118	            // Dropping a response stream means the client stopped consuming; propagate
119	            // cancellation to Python without blocking the Tokio worker.
120	            spawn_abort(self.bridge.clone(), self.rid.clone());
121	        }
122	    }
123	}
124	
125	fn spawn_abort(bridge: Arc<PyBridge>, rid: String) {
126	    match tokio::runtime::Handle::try_current() {
127	        Ok(handle) => {
128	            let _ = handle.spawn_blocking(move || {
129	                let _ = bridge.abort(&rid, false);
130	            });
131	        }
132	        Err(_) => {
133	            tracing::warn!(
134	                rid,
135	                "Skipping gRPC request abort because no Tokio runtime is available"
136	            );
137	        }
138	    }
139	}
140	
141	async fn recv_terminal_chunk_for_request(
142	    bridge: &Arc<PyBridge>,
143	    rid: &str,
144	    receiver: &mut Receiver<ResponseChunk>,
145	    response_timeout: Duration,
146	) -> Result<ResponseChunk, Status> {
147	    let mut abort_guard = RequestAbortGuard::new(bridge.clone(), rid.to_string());
148	
149	    match recv_chunk_with_timeout(receiver, response_timeout, || {
150	        format!("Request timed out after {}s", response_timeout.as_secs())
151	    })
152	    .await
153	    {
154	        Ok(Some(ResponseChunk::Data(_))) => {
155	            tracing::warn!(
156	                rid,
157	                "Unary gRPC response received non-terminal Data chunk; expected Finished"
158	            );
159	            abort_guard.abort_now();
160	            Err(Status::internal(
161	                "Unary response protocol violation: expected Finished, got Data",
162	            ))
163	        }
164	        Ok(Some(chunk @ (ResponseChunk::Finished(_) | ResponseChunk::Error(_)))) => {
165	            abort_guard.disarm();
166	            Ok(chunk)
167	        }
168	        Ok(None) => {
169	            let (status, should_abort) = closed_stream_status(bridge, rid);
170	            if should_abort {
171	                abort_guard.abort_now();
172	            } else {
173	                abort_guard.disarm();
174	            }
175	            Err(status)
176	        }
177	        Err(status) => {
178	            if status.code() == tonic::Code::DeadlineExceeded {
179	                abort_guard.abort_now();
180	            } else {
181	                abort_guard.disarm();
182	            }
183	            Err(status)
184	        }
185	    }
186	}
187	
188	fn closed_stream_status(bridge: &Arc<PyBridge>, rid: &str) -> (Status, bool) {
189	    if let Some(error) = bridge.take_terminal_error(rid) {
190	        (terminal_error_status(error), false)
191	    } else {
192	        (
193	            Status::internal("gRPC response stream closed before a terminal response"),
194	            true,
195	        )
196	    }
197	}
198	
199	fn terminal_error_status(error: TerminalError) -> Status {
200	    let message = error.message();
201	    match error {
202	        TerminalError::ChannelFull { .. } => Status::resource_exhausted(message),
203	        TerminalError::ClientDisconnected { .. } | TerminalError::Aborted { .. } => {
204	            Status::cancelled(message)
205	        }
206	    }
207	}
