261	                    }
262	                    Ok(Some(ResponseChunk::Error(msg))) => {
263	                        abort_guard.disarm();
264	                        yield Err(Status::internal(msg));
265	                        break;
266	                    }
267	                    Ok(None) => {
268	                        let (status, should_abort) = closed_stream_status(&bridge, &rid_clone);
