472	    // --- SGLang-native RPCs: Tokenize / Detokenize (Rust-native with fallback) ---
473	
474	    async fn tokenize(
475	        &self,
476	        request: Request<proto::TokenizeRequest>,
477	    ) -> Result<Response<proto::TokenizeResponse>, Status> {
478	        let req = request.into_inner();
479	        let add_special = req.add_special_tokens.unwrap_or(true);
480	
481	        // Try Rust-native tokenizer first (no GIL)
482	        if let Some(tok) = self.bridge.rust_tokenizer() {
483	            let tokens = tok
484	                .encode(&req.text, add_special)
485	                .map_err(Status::internal)?;
486	            let count = tokens.len() as i32;
487	            return Ok(Response::new(proto::TokenizeResponse {
488	                tokens: tokens.iter().map(|&t| t as i32).collect(),
489	                count,
490	                max_model_len: self.bridge.context_len(),
491	                input_text: req.text,
492	            }));
493	        }
494	
495	        // Fallback to Python
496	        let json_str = tokio::task::spawn_blocking({
497	            let bridge = self.bridge.clone();
498	            let text = req.text.clone();
499	            move || bridge.tokenize_py(&text, add_special)
500	        })
501	        .await
502	        .map_err(|e| Status::internal(format!("Task join error: {}", e)))?
503	        .map_err(|e| pyerr_to_status(e, "Tokenize failed"))?;
504	
505	        let v: serde_json::Value = serde_json::from_str(&json_str)
506	            .map_err(|e| Status::internal(format!("Failed to parse JSON response: {}", e)))?;
507	        Ok(Response::new(proto::TokenizeResponse {
508	            tokens: v["tokens"]
509	                .as_array()
510	                .map(|a| {
511	                    a.iter()
512	                        .filter_map(|x| x.as_i64().map(|n| n as i32))
513	                        .collect()
514	                })
515	                .unwrap_or_default(),
516	            count: v["count"].as_i64().unwrap_or(0) as i32,
517	            max_model_len: self.bridge.context_len(),
518	            input_text: req.text,
519	        }))
520	    }
