449	fn close_channel_with_error(
450	    py: Python<'_>,
451	    rid: &str,
452	    state: &BridgeStateRef,
453	    runtime_handle: &PyObject,
454	    error: TerminalError,
455	) {
456	    let mut state = lock_or_recover(state.as_ref(), "state");
457	    remove_channel_refs_locked(&mut state, rid);
458	    state.terminal_errors.insert(rid.to_string(), error);
459	    drop(state);
460	    let _ = runtime_handle.call_method1(py, "abort", (rid, false));
461	}
462	
463	fn remove_channel_refs_locked(state: &mut BridgeState, rid: &str) -> bool {
464	    let had_channel = state.channels.remove(rid).is_some();
465	    let had_pending = state.pending_sends.remove(rid);
466	    let had_callback = state.ready_callbacks.remove(rid).is_some();
467	    let had_signal = state.ready_signals.remove(rid);
468	    had_channel || had_pending || had_callback || had_signal
469	}
470	
471	fn remove_channel_refs(rid: &str, state: &BridgeStateRef) {
472	    let mut state = lock_or_recover(state.as_ref(), "state");
473	    remove_channel_refs_locked(&mut state, rid);
474	}
