476	fn register_pending_send(rid: &str, state: &BridgeStateRef) -> bool {
477	    let mut state = lock_or_recover(state.as_ref(), "state");
478	    state.pending_sends.insert(rid.to_string())
479	}
480	
481	fn mark_send_ready(py: Python<'_>, rid: &str, state: &BridgeStateRef) -> Option<PyObject> {
482	    let mut state = lock_or_recover(state.as_ref(), "state");
483	    state.pending_sends.remove(rid);
484	    if let Some(callback) = state.ready_callbacks.get(rid) {
485	        Some(callback.clone_ref(py))
486	    } else {
487	        state.ready_signals.insert(rid.to_string());
488	        None
489	    }
490	}
491	
492	fn notify_ready(py: Python<'_>, rid: &str, callback: PyObject) {
493	    if let Err(err) = callback.call0(py) {
494	        tracing::warn!(rid, "gRPC on_ready callback failed: {}", err);
495	    }
496	}
497	
498	fn set_on_ready_for_rid(
499	    py: Python<'_>,
500	    rid: &str,
501	    state: &BridgeStateRef,
502	    on_ready: PyObject,
503	) -> PyResult<()> {
504	    let should_notify = {
505	        let mut state = lock_or_recover(state.as_ref(), "state");
506	        state
507	            .ready_callbacks
508	            .insert(rid.to_string(), on_ready.clone_ref(py));
509	        state.ready_signals.remove(rid)
510	    };
511	    if should_notify {
512	        on_ready.call0(py)?;
513	    }
514	    Ok(())
515	}
516	
517	fn clear_on_ready_for_rid(rid: &str, state: &BridgeStateRef) {
518	    // End notifications for this rid. Do not call set_on_ready again for the same rid.
519	    let mut state = lock_or_recover(state.as_ref(), "state");
520	    state.ready_callbacks.remove(rid);
521	    state.ready_signals.remove(rid);
522	}
523	
524	fn try_send_chunk(
525	    py: Python<'_>,
526	    rid: &str,
527	    state: &BridgeStateRef,
528	    runtime_handle: &PyObject,
529	    tokio_handle: &Handle,
530	    sender: &Sender<ResponseChunk>,
531	    msg: ResponseChunk,
532	) -> PyResult<ChunkSendStatus> {
533	    let terminal = msg.is_terminal();
534	    match sender.try_send(msg) {
535	        Ok(()) => {
536	            if terminal {
537	                remove_channel_refs(rid, state);
538	            }
539	            Ok(ChunkSendStatus::Ready)
540	        }
541	        Err(TrySendError::Full(msg)) => {
542	            if !register_pending_send(rid, state) {
543	                tracing::warn!(
544	                    rid,
545	                    "gRPC bridge received another chunk before the parked chunk drained; closing stream"
546	                );
547	                close_channel_with_error(
548	                    py,
549	                    rid,
550	                    state,
551	                    runtime_handle,
552	                    TerminalError::ChannelFull { rid: rid.into() },
553	                );
554	                return Ok(ChunkSendStatus::Closed);
555	            }
556	
557	            let rid_owned = rid.to_string();
558	            let state = state.clone();
559	            let runtime_handle = runtime_handle.clone_ref(py);
560	            let sender = sender.clone();
561	
562	            tokio_handle.spawn(async move {
563	                match sender.send(msg).await {
564	                    Ok(()) => {
565	                        if terminal {
566	                            // Terminal chunks end the producer contract; no further on_ready
567	                            // signal is fired after a parked Finished/Error drains.
568	                            remove_channel_refs(&rid_owned, &state);
569	                            return;
570	                        }
571	
572	                        Python::with_gil(|py| {
573	                            if let Some(callback) = mark_send_ready(py, &rid_owned, &state) {
574	                                notify_ready(py, &rid_owned, callback);
575	                            }
576	                        });
577	                    }
578	                    Err(_) => {
579	                        Python::with_gil(|py| {
580	                            close_channel_with_error(
581	                                py,
582	                                &rid_owned,
583	                                &state,
584	                                &runtime_handle,
585	                                TerminalError::ClientDisconnected {
586	                                    rid: rid_owned.clone(),
587	                                },
588	                            );
589	                        });
590	                    }
591	                }
592	            });
593	
594	            Ok(ChunkSendStatus::Pending)
595	        }
596	        Err(TrySendError::Closed(_)) => {
597	            close_channel_with_error(
598	                py,
599	                rid,
600	                state,
601	                runtime_handle,
602	                TerminalError::ClientDisconnected { rid: rid.into() },
603	            );
604	            Ok(ChunkSendStatus::Closed)
605	        }
606	    }
607	}
