609	// Typed chunk callback for SGLang-native RPCs (dict-based chunks).
610	#[pyclass]
611	struct ChunkCallback {
612	    rid: String,
613	    state: BridgeStateRef,
614	    runtime_handle: PyObject,
615	    tokio_handle: Handle,
616	}
617	
618	#[pymethods]
619	impl ChunkCallback {
620	    /// Register before producing chunks. If a parked chunk drained before registration,
621	    /// Rust fires `on_ready` immediately so late registration cannot miss the edge.
622	    fn set_on_ready(&self, py: Python<'_>, on_ready: PyObject) -> PyResult<()> {
623	        set_on_ready_for_rid(py, &self.rid, &self.state, on_ready)
624	    }
625	
626	    fn clear_on_ready(&self) {
627	        clear_on_ready_for_rid(&self.rid, &self.state);
628	    }
629	
630	    #[pyo3(signature = (chunk, finished=false, error=None))]
631	    fn __call__(
632	        &self,
633	        chunk: &Bound<'_, PyDict>,
634	        finished: bool,
635	        error: Option<String>,
636	    ) -> PyResult<ChunkSendStatus> {
637	        let py = chunk.py();
638	        let state = lock_or_recover(self.state.as_ref(), "state");
639	        let sender = match state.channels.get(&self.rid) {
640	            Some(s) => s.clone(),
641	            None => return Ok(ChunkSendStatus::Closed),
642	        };
643	        drop(state);
644	
645	        if let Some(err_msg) = error {
646	            return try_send_chunk(
647	                py,
648	                &self.rid,
649	                &self.state,
650	                &self.runtime_handle,
651	                &self.tokio_handle,
652	                &sender,
653	                ResponseChunk::Error(err_msg),
654	            );
655	        }
656	
657	        let text: Option<String> = chunk
658	            .get_item("text")?
659	            .and_then(|v| v.extract::<String>().ok());
660	
661	        let output_ids: Option<Vec<i32>> = chunk
662	            .get_item("output_ids")?
663	            .and_then(|v| v.extract::<Vec<i32>>().ok());
664	
665	        let embedding: Option<Vec<f32>> = chunk
666	            .get_item("embedding")?
667	            .and_then(|v| v.extract::<Vec<f32>>().ok());
668	
669	        let meta_info = extract_meta_info(chunk);
670	
671	        let data = ResponseData {
672	            text,
673	            output_ids,
674	            embedding,
675	            json_bytes: None,
676	            meta_info,
677	        };
678	
679	        let msg = if finished {
680	            ResponseChunk::Finished(data)
681	        } else {
682	            ResponseChunk::Data(data)
683	        };
684	
685	        try_send_chunk(
686	            py,
687	            &self.rid,
688	            &self.state,
689	            &self.runtime_handle,
690	            &self.tokio_handle,
691	            &sender,
692	            msg,
693	        )
694	    }
695	}
