706	#[pymethods]
707	impl JsonChunkCallback {
708	    /// Register before producing chunks. If a parked chunk drained before registration,
709	    /// Rust fires `on_ready` immediately so late registration cannot miss the edge.
710	    fn set_on_ready(&self, py: Python<'_>, on_ready: PyObject) -> PyResult<()> {
711	        set_on_ready_for_rid(py, &self.rid, &self.state, on_ready)
712	    }
713	
714	    fn clear_on_ready(&self) {
715	        clear_on_ready_for_rid(&self.rid, &self.state);
716	    }
717	
718	    #[pyo3(signature = (chunk_bytes, finished=false, error=None, status_code=None))]
719	    fn __call__(
720	        &self,
721	        chunk_bytes: &Bound<'_, pyo3::PyAny>,
722	        finished: bool,
723	        error: Option<String>,
724	        status_code: Option<i32>,
725	    ) -> PyResult<ChunkSendStatus> {
726	        let py = chunk_bytes.py();
727	        let state = lock_or_recover(self.state.as_ref(), "state");
728	        let sender = match state.channels.get(&self.rid) {
729	            Some(s) => s.clone(),
730	            None => return Ok(ChunkSendStatus::Closed),
731	        };
732	        drop(state);
733	
734	        if let Some(err_msg) = error {
735	            return try_send_chunk(
736	                py,
737	                &self.rid,
738	                &self.state,
739	                &self.runtime_handle,
740	                &self.tokio_handle,
741	                &sender,
742	                ResponseChunk::Error(err_msg),
743	            );
744	        }
745	
746	        let bytes_data: Vec<u8> = if let Ok(b) = chunk_bytes.extract::<Vec<u8>>() {
747	            b
748	        } else if let Ok(s) = chunk_bytes.extract::<String>() {
749	            s.into_bytes()
750	        } else {
751	            vec![]
752	        };
753	
754	        let mut meta_info = HashMap::new();
755	        if let Some(code) = status_code {
756	            meta_info.insert("status_code".to_string(), code.to_string());
757	        }
758	
759	        let data = ResponseData {
760	            text: None,
761	            output_ids: None,
762	            embedding: None,
763	            json_bytes: Some(bytes_data),
764	            meta_info,
765	        };
766	
767	        let msg = if finished {
768	            ResponseChunk::Finished(data)
769	        } else {
770	            ResponseChunk::Data(data)
771	        };
772	
773	        try_send_chunk(
774	            py,
775	            &self.rid,
776	            &self.state,
777	            &self.runtime_handle,
778	            &self.tokio_handle,
779	            &sender,
780	            msg,
781	        )
782	    }
783	}
784	
785	fn extract_meta_info(chunk: &Bound<'_, PyDict>) -> HashMap<String, String> {
786	    let mut meta = HashMap::new();
787	    if let Ok(Some(meta_obj)) = chunk.get_item("meta_info")
788	        && let Ok(meta_dict) = meta_obj.downcast::<PyDict>()
789	    {
790	        for (k, v) in meta_dict.iter() {
791	            // The proto schema is map<string, string>; encode each Python value as JSON
792	            // so clients can recover numbers, booleans, arrays, and objects losslessly.
793	            if let Ok(key) = k.extract::<String>()
794	                && let Ok(val) = py_value_to_json_string(&v)
795	            {
796	                meta.insert(key, val);
797	            }
798	        }
799	    }
800	    meta
801	}
